#include "e_paper.h"
#include <GxEPD2_BW.h>
#include <Fonts/FreeMonoBold9pt7b.h>
static GxEPD2_BW<GxEPD2_290_T5,GxEPD2_290_T5::HEIGHT> display(GxEPD2_290_T5(5,17,16,4));
void epaper_setup(){display.init(115200);display.setRotation(1);display.setTextColor(GxEPD_BLACK);Serial.println("[epaper] OK");}
void epaper_clear(){display.setFullWindow();display.firstPage();do{display.fillScreen(GxEPD_WHITE);}while(display.nextPage());}
void epaper_text(int x,int y,const char*t,int s){display.setFont(&FreeMonoBold9pt7b);display.setCursor(x,y);display.print(t);}
void epaper_update(){display.display();}
